UPDATE t_p71821556_real_estate_catalog_.districts SET description = CASE id
  WHEN 10 THEN 'Плотно заселённый спальный район с высоким пешеходным трафиком — идеален для магазинов у дома, аптек, салонов красоты и кафе. Ул. 40 лет Победы — активная торговая ось. Стрит-ритейл на первых этажах стабильно востребован. Хорошая база для сетевых форматов и франшиз.'
  WHEN 11 THEN 'Промышленно-складская зона на юго-востоке города. Близость к трассе М4 «Дон» делает район привлекательным для логистики, автосервисов, оптовых баз и производств. Низкая арендная ставка при большой площади — здесь выгодно размещать склады класса B и распределительные центры.'
  WHEN 12 THEN 'Район рядом с аэропортом (до 2023 г.) с активной реновацией. Интересен для гостиниц, хостелов, автомоек, сервисных центров. Активная жилая застройка формирует спрос на бытовые услуги и торговлю. Перспективен по мере роста жилых кварталов.'
  WHEN 13 THEN 'Зона транспортного узла у бывшего аэропорта. Высокий транзитный трафик по ул. Дзержинского. Привлекателен для автосервисов, шиномонтажей, мелкооптовой торговли, складов и производственных цехов. Относительно низкие арендные ставки.'
  WHEN 14 THEN 'Малоэтажный посёлок с частным сектором на севере Краснодара. Спрос на коммерческую недвижимость ограничен, актуальны форматы районного масштаба: небольшие магазины, парикмахерские, ремонтные мастерские. Подходит для небольших складов и мелкого производства.'
  WHEN 15 THEN 'Исторически производственный район с рядом действующих предприятий. Оптимален для размещения производств, техобслуживания, складов и мастерских. Арендные ставки ниже среднегородских, есть корпуса с высокими потолками и подъездными путями.'
  WHEN 16 THEN 'Крупный жилой массив с развитой инфраструктурой. ТЦ «Красная Площадь» создаёт мощный торговый кластер. Высокий спрос на стрит-ритейл вдоль ул. им. Героя Яцкова и Ставропольской. Хорош для общепита, медицинских клиник, спортивных студий и магазинов товаров повседневного спроса.'
  WHEN 17 THEN 'Новый элитный жилой район с обеспеченной аудиторией. Высокий средний чек — привлекателен для бутиков, ресторанов, фитнес-клубов и частных медицинских центров. Коммерческие помещения встроены в жилые комплексы, стабильный трафик жителей круглый год.'
  WHEN 18 THEN 'Престижный коттеджный посёлок с состоятельным населением. Идеален для бутиков, салонов красоты premium-класса, частных клиник и ресторанов с высоким средним чеком. Спрос на офисы для небольших частных практик (юристы, врачи, психологи).'
  WHEN 19 THEN 'Бывшая промышленная зона в активной стадии реновации. Склады и производственные корпуса сочетаются с первыми новыми жилыми домами. Выгоден для размещения производств, мастерских, шоурумов и складов. Арендные ставки умеренные, есть большие площади.'
  WHEN 20 THEN 'Стратегическая логистическая зона вдоль трассы Западного обхода Краснодара. Лучшее место для крупных складских комплексов, распределительных центров, логистических хабов и производств с грузовым транспортом. Прямой выход на федеральные трассы без заезда в город.'
  WHEN 21 THEN 'Садоводческий массив с постепенной урбанизацией. Коммерческая привлекательность ограничена — актуальны небольшие магазины, сезонная торговля, хозяйственные магазины. Перспективен при развитии жилой застройки в окружении.'
  WHEN 22 THEN 'Небольшой посёлок с частной застройкой. Коммерческий потенциал ограничен локальным спросом жителей. Подходит для небольших продуктовых магазинов, мастерских и бытовых услуг.'
  WHEN 23 THEN 'Промышленный район вдоль берега Кубани. Исторически здесь работали крупные производства — сейчас территория перестраивается. Интересен для производств, складов, шоурумов и мастерских. Близость к реке и центру делает часть площадок перспективными под редевелопмент.'
  WHEN 24 THEN 'Один из крупнейших спальных районов города с высоким пешеходным трафиком. Ставропольская улица — мощная торговая артерия с трафиком 30 000+ авт/сутки. Спрос на все форматы: супермаркеты, аптеки, кафе, фитнес. ТЦ «Галактика» задаёт ритм торговле. Отличная локация для сетевых операторов.'
  WHEN 25 THEN 'Медицинский кластер с высокой концентрацией клиник и больниц. Идеален для медицинских центров, аптек, оптик, медтехники и реабилитационных услуг. Стабильный поток пациентов и персонала создаёт спрос на кафе, аптеки и бытовые услуги поблизости.'
  WHEN 26 THEN 'Топовая торговая локация Краснодара — ТЦ «Красная Площадь» является крупнейшим ТЦ ЮФО. Якорная зона для fashion, ресторанов, развлечений и услуг. Максимальный трафик в городе, но и наивысшие ставки аренды. Оптимально для брендов федерального уровня.'
  WHEN 27 THEN 'Посёлок на западной окраине. Коммерческая активность невысокая, актуальны форматы местного масштаба. Интересен для размещения складов и мелкого производства благодаря низким ставкам и наличию земли.'
  WHEN 28 THEN 'Район бывшего камвольно-суконного комбината с промышленными корпусами. Часть зданий перепрофилирована под склады, мастерские и производства. Привлекателен для бизнеса, которому нужны большие площади по умеренным ценам с возможностью размещения оборудования.'
  WHEN 29 THEN 'Растущий жилой посёлок. С увеличением населения формируется спрос на бытовые услуги, торговлю и общепит. Ранний вход в локацию сейчас обеспечит выгодные долгосрочные условия аренды при росте трафика.'
  WHEN 30 THEN 'Плотный жилой район с развитой инфраструктурой. Активный пешеходный трафик создаёт спрос на ритейл, кафе, аптеки, детские центры. Коммерческие помещения в первых этажах домов пользуются стабильным спросом. Подходит для небольшого бизнеса с местной аудиторией.'
  WHEN 31 THEN 'Производственно-жилой посёлок с промышленными предприятиями. Оптимален для размещения производств, автосервисов, складских помещений. Низкие ставки и наличие помещений с высокими потолками и подъездными путями.'
  WHEN 32 THEN 'Современный район с высокоплатёжной аудиторией. Развита торговая инфраструктура, высокий пешеходный трафик вдоль центральных улиц. Востребованы кафе, рестораны, фитнес-студии, медицинские центры. Коммерческие помещения в новостройках — хорошая инвестиция в растущей локации.'
  WHEN 33 THEN 'Активно развивающийся жилой район с новыми ЖК. Быстро растущее население создаёт спрос на весь спектр услуг. Отличная возможность войти в перспективную локацию на ранней стадии: пекарни, медицинские кабинеты, детские студии, фитнес, кофейни — всё будет востребовано.'
  WHEN 34 THEN 'Медицинский кластер с крупным офтальмологическим центром. Поток пациентов и медперсонала формирует устойчивый спрос на аптеки, оптику, медтехнику, кафе и бытовые услуги. Интересен для смежного медицинского бизнеса и реабилитационных центров.'
  WHEN 35 THEN 'Молодой жилой район с активной застройкой. Молодёжная аудитория с формирующимся потреблением — спрос на кафе, барбершопы, фитнес, образование. Перспективен для первопроходцев — ставки аренды пока умеренные при быстром росте трафика.'
  WHEN 36 THEN 'Развивающийся посёлок на юге города. Постепенная урбанизация открывает возможности для раннего старта торгового бизнеса. Актуальны форматы первой необходимости: продукты, аптека, бытовые услуги.'
  WHEN 37 THEN 'Крупный район с аэропортом (действует). Высокий транзитный трафик с аэропортовой составляющей. Привлекателен для гостиниц, хостелов, кафе и ресторанов. Развитая жилая среда создаёт локальный спрос на торговлю и бытовые услуги. Промзона в составе района — возможности для производств и складов.'
  WHEN 38 THEN 'Малоэтажный посёлок с частным сектором. Коммерческий потенциал ограничен — подходит для небольших мастерских, агросервиса или мелкой производственной деятельности с минимальными вложениями.'
  WHEN 39 THEN 'Посёлок с частной застройкой на юго-западе города. Коммерческая активность низкая. Актуальны небольшие магазины товаров первой необходимости и мастерские для местных жителей.'
  WHEN 40 THEN 'Бывшая заводская территория с корпусами производственного назначения. Ряд зданий пригоден для размещения производств, складов, сервисных цехов. Привлекателен для технического бизнеса, нуждающегося в больших площадях с электрическими мощностями.'
  WHEN 41 THEN 'Развивающийся посёлок на востоке города. Идёт активная жилая застройка — формируется спрос на торговлю и услуги для новосёлов. Стратегически выгоден для открытия бизнеса «первым в локации» — конкуренция минимальна.'
  WHEN 42 THEN 'Активно застраивающийся посёлок с высоким приростом населения. Спрос на услуги и торговлю растёт вместе с числом жителей. Перспективен для супермаркетов шаговой доступности, кофеен, медпунктов, детских центров. Аренда пока доступная — хорошее время для старта.'
  WHEN 43 THEN 'Университетский район с высокой концентрацией студентов и преподавателей. Отличная локация для кафе, столовых, копировальных центров, книжных, ремонта техники и молодёжного ритейла. Стабильный поток аудитории в учебные периоды с ярко выраженной сезонностью.'
  WHEN 44 THEN 'Крупный жилой район с активной торговой средой. Высокий пешеходный трафик на ключевых улицах. Развиты все форматы коммерческой недвижимости — от стрит-ритейла до встроенных офисов. Привлекателен для продуктовых операторов, аптечных сетей, банков и медицинских клиник.'
  WHEN 45 THEN 'Престижный спортивно-развлекательный район с стадионом «Краснодар» и парком. Высокий трафик в дни матчей и выходные. Идеален для ресторанов, баров, спортивных магазинов, гостиниц и развлекательных заведений. Один из самых перспективных районов для вложений в коммерческую недвижимость.'
  WHEN 46 THEN 'Район реновации промышленного наследия в пешей доступности от центра. Лофт-пространства и бывшие заводские корпуса — тренд для креативных офисов, студий, шоурумов, ресторанов в индустриальном стиле. Один из самых перспективных районов по соотношению цена/локация.'
  WHEN 47 THEN 'Промышленная зона с энергетической инфраструктурой. Оптимален для производств с высокими энергопотребностями, складов и технических предприятий. Наличие мощных электрических сетей — конкурентное преимущество для ряда производственных направлений.'
  WHEN 48 THEN 'Один из самых больших и заселённых районов города. Высокий пешеходный трафик, развитая торговля. ТЦ «МегаМаг» и «Галерея» формируют мощный торговый кластер. Отлично подходит для всех форматов ритейла, общепита и бытовых услуг. Стабильный спрос при любой конъюнктуре.'
  WHEN 49 THEN 'Район с промышленным прошлым и трансформирующейся средой. Доступные площади производственного назначения при близости к городской инфраструктуре. Подходит для лёгкого производства, складов, мастерских и технических сервисов.'
  WHEN 50 THEN 'Деловое сердце Краснодара. Максимальная концентрация офисов класса А и В, банков, ресторанов, отелей и флагманских магазинов. Ул. Красная — главная торговая артерия юга России. Здесь располагаются головные офисы компаний, представительства, шоурумы. Самые высокие ставки аренды, но и самый высокий статус адреса.'
  WHEN 51 THEN 'Крупный многоэтажный район с развитой бытовой инфраструктурой. Стабильный спрос на стрит-ритейл первых этажей, медицинские услуги, кафе и торговлю. Хороший вариант для сетевых операторов, ищущих точки в жилых массивах с гарантированным трафиком.'
  WHEN 52 THEN 'Динамичный жилой район с большим количеством школ и детских садов. Высокий спрос на детские развивающие центры, образовательные студии, медицинские кабинеты. Семейная аудитория хорошо реагирует на кафе, булочные и магазины с качественными продуктами.'
  WHEN 53 THEN 'Активно застраивающийся район вдоль ул. Жукова. Новые жилые комплексы формируют растущую аудиторию потребителей. Спрос на все виды услуг опережает предложение — хорошая возможность занять нишу в недонасыщенной локации. Перспективен для кафе, фитнеса, детских студий.'
  WHEN 54 THEN 'Современный жилой район с молодой и платёжеспособной аудиторией. Вдоль ул. Героев-Разведчиков сформировалась активная торговая полоса. Спрос на рестораны, кофейни, фитнес, медицину и детские услуги. Устойчивый рост стоимости недвижимости делает район привлекательным для инвестиций.'
  ELSE description
END
WHERE is_active = TRUE;